protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Blog>(entity =>
    {
        // BC1: Discriminator property renamed from "Discriminator" to "$type" in EF 9.
        // Existing documents use the old name, so keep it.
        entity.HasDiscriminator<string>("Discriminator");

        // BC2: id value no longer includes the discriminator (was "Blog|1", now "1").
        // Restore the old composite format for existing documents.
        entity.HasDiscriminatorInJsonId();

        // BC3: Key property now maps directly to JSON "id"; previously a shadow
        // __id property was used and the key was stored separately in the document.
        // Restore the shadow property so existing documents stay compatible.
        entity.HasShadowId();
    });

    // BC4: HasIndex() now throws — Cosmos indexes all properties by default.
    // Removed: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
}

